import React, { useState, useEffect } from 'react';
import { TrendingUp, TrendingDown, Check, X, LogOut, Zap } from 'lucide-react';

const BaileysGauge = () => {
  const [page, setPage] = useState('landing');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [scanResults, setScanResults] = useState([]);
  const [watchlist, setWatchlist] = useState([]);
  const [authForm, setAuthForm] = useState({ email: '', password: '', name: '' });
  const [isSignUp, setIsSignUp] = useState(false);
  const [scanInput, setScanInput] = useState('AAPL,MSFT,GOOGL,AMZN,TSLA');
  const [error, setError] = useState('');

  const API = 'http://localhost:5001/api';

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      fetchUser(token);
    }
  }, []);

  const fetchUser = async (token) => {
    try {
      const res = await fetch(`${API}/user`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      setUser(data);
      setIsLoggedIn(true);
    } catch (err) {
      console.error('Error fetching user');
    }
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const endpoint = isSignUp ? `${API}/auth/register` : `${API}/auth/login`;

    try {
      const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(isSignUp 
          ? { ...authForm }
          : { email: authForm.email, password: authForm.password }
        )
      });

      const data = await res.json();

      if (data.token) {
        localStorage.setItem('token', data.token);
        setUser(data.user);
        setIsLoggedIn(true);
        setPage('dashboard');
        setAuthForm({ email: '', password: '', name: '' });
      } else {
        setError(data.error || 'Authentication failed');
      }
    } catch (err) {
      setError('Error: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleScan = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const tickers = scanInput.split(',').map(t => t.trim().toUpperCase()).filter(Boolean);
    const token = localStorage.getItem('token');

    try {
      const res = await fetch(`${API}/scan`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ tickers })
      });

      const data = await res.json();

      if (data.results) {
        setScanResults(data.results);
      } else {
        setError(data.error || 'Scan failed');
      }
    } catch (err) {
      setError('Scan error: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const addToWatchlist = (ticker) => {
    if (!watchlist.includes(ticker)) {
      setWatchlist([...watchlist, ticker]);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setIsLoggedIn(false);
    setUser(null);
    setPage('landing');
  };

  const handleUpgrade = (plan) => {
    const token = localStorage.getItem('token');
    // Mock upgrade - in production, this goes to Stripe
    if (user) {
      setUser({ ...user, plan });
      setPage('dashboard');
    }
  };

  // ==================== LANDING PAGE ====================
  const LandingPage = () => (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)' }}>
      <nav style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        padding: '1.5rem 2rem',
        background: 'rgba(15, 23, 42, 0.95)',
        borderBottom: '1px solid rgba(148, 163, 184, 0.1)'
      }}>
        <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#10b981', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <TrendingUp size={28} /> Bailey's Gauge
        </div>
        <button
          onClick={() => { setIsSignUp(false); setPage('auth'); }}
          style={{
            padding: '0.75rem 1.5rem',
            background: '#10b981',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            cursor: 'pointer',
            fontWeight: 'bold'
          }}
        >
          Sign In
        </button>
      </nav>

      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '4rem 2rem' }}>
        <h1 style={{
          fontSize: '56px',
          fontWeight: 'bold',
          color: 'white',
          marginBottom: '1rem',
          textAlign: 'center'
        }}>
          Professional Stock Scanner
        </h1>
        <p style={{
          fontSize: '20px',
          color: '#94a3b8',
          textAlign: 'center',
          marginBottom: '2rem'
        }}>
          Find winning trades with technical, fundamental & price action analysis.
        </p>

        <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center', marginBottom: '4rem' }}>
          <button
            onClick={() => { setIsSignUp(true); setPage('auth'); }}
            style={{
              padding: '1rem 2rem',
              background: '#10b981',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: 'pointer',
              fontWeight: 'bold',
              fontSize: '16px'
            }}
          >
            Get Started Free
          </button>
          <button
            onClick={() => setPage('pricing')}
            style={{
              padding: '1rem 2rem',
              background: 'transparent',
              color: '#10b981',
              border: '2px solid #10b981',
              borderRadius: '8px',
              cursor: 'pointer',
              fontWeight: 'bold',
              fontSize: '16px'
            }}
          >
            View Pricing
          </button>
        </div>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
          gap: '2rem'
        }}>
          {[
            { emoji: '📊', title: 'Technical Analysis', desc: 'RSI, MACD, Bollinger Bands' },
            { emoji: '💰', title: 'Fundamental Data', desc: 'P/E, Dividends, ROE' },
            { emoji: '🎯', title: 'Price Action', desc: 'Breakouts & Volume' },
            { emoji: '⭐', title: 'Smart Scoring', desc: 'AI-powered signals' },
            { emoji: '🔔', title: 'Price Alerts', desc: 'Real-time notifications' },
            { emoji: '📈', title: 'Portfolio Tracker', desc: 'Manage positions' }
          ].map((f, i) => (
            <div key={i} style={{
              background: 'rgba(30, 41, 59, 0.8)',
              border: '1px solid rgba(148, 163, 184, 0.2)',
              borderRadius: '12px',
              padding: '2rem',
              textAlign: 'center'
            }}>
              <div style={{ fontSize: '40px', marginBottom: '1rem' }}>{f.emoji}</div>
              <h3 style={{ fontSize: '18px', fontWeight: 'bold', color: 'white', marginBottom: '0.5rem' }}>{f.title}</h3>
              <p style={{ color: '#94a3b8', fontSize: '14px' }}>{f.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  // ==================== PRICING PAGE ====================
  const PricingPage = () => (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)', paddingTop: '2rem' }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem' }}>
        <button
          onClick={() => setPage('landing')}
          style={{
            padding: '0.5rem 1rem',
            background: 'transparent',
            color: '#10b981',
            border: '1px solid #10b981',
            borderRadius: '6px',
            cursor: 'pointer',
            marginBottom: '2rem'
          }}
        >
          ← Back
        </button>

        <h2 style={{ fontSize: '40px', fontWeight: 'bold', color: 'white', textAlign: 'center', marginBottom: '3rem' }}>
          Simple, Transparent Pricing
        </h2>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '2rem' }}>
          {[
            {
              name: 'Free',
              price: '$0',
              features: [
                { text: 'Scan up to 5 stocks', included: true },
                { text: '7-day data retention', included: true },
                { text: 'Basic indicators', included: true },
                { text: 'Unlimited scans', included: false },
                { text: 'API access', included: false },
              ]
            },
            {
              name: 'Pro',
              price: '$29.99',
              period: '/month',
              highlighted: true,
              features: [
                { text: 'Unlimited scans', included: true },
                { text: '1-year data retention', included: true },
                { text: 'All indicators', included: true },
                { text: 'Price alerts', included: true },
                { text: 'Portfolio management', included: true },
              ]
            },
            {
              name: 'Enterprise',
              price: '$99.99',
              period: '/month',
              features: [
                { text: 'Everything in Pro', included: true },
                { text: 'API access', included: true },
                { text: 'Webhook integration', included: true },
                { text: 'Custom filters', included: true },
                { text: 'Priority support', included: true },
              ]
            }
          ].map((plan, i) => (
            <div key={i} style={{
              background: plan.highlighted ? 'rgba(16, 185, 129, 0.1)' : 'rgba(30, 41, 59, 0.8)',
              border: plan.highlighted ? '2px solid #10b981' : '1px solid rgba(148, 163, 184, 0.2)',
              borderRadius: '12px',
              padding: '2rem'
            }}>
              <h3 style={{ fontSize: '24px', fontWeight: 'bold', color: 'white', marginBottom: '1rem' }}>
                {plan.name}
              </h3>
              <div style={{ marginBottom: '2rem' }}>
                <span style={{ fontSize: '40px', fontWeight: 'bold', color: '#10b981' }}>
                  {plan.price}
                </span>
                {plan.period && <span style={{ color: '#94a3b8' }}>{plan.period}</span>}
              </div>

              <ul style={{ listStyle: 'none', padding: '0', marginBottom: '2rem' }}>
                {plan.features.map((feature, j) => (
                  <li key={j} style={{
                    padding: '0.75rem 0',
                    borderBottom: '1px solid rgba(148, 163, 184, 0.1)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.75rem',
                    color: feature.included ? 'white' : '#64748b'
                  }}>
                    {feature.included ? <Check size={18} color="#10b981" /> : <X size={18} />}
                    {feature.text}
                  </li>
                ))}
              </ul>

              <button
                onClick={() => { setIsSignUp(true); setPage('auth'); }}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  background: plan.highlighted ? '#10b981' : 'transparent',
                  color: plan.highlighted ? 'white' : '#10b981',
                  border: plan.highlighted ? 'none' : '2px solid #10b981',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontWeight: 'bold'
                }}
              >
                Get Started
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  // ==================== AUTH PAGE ====================
  const AuthPage = () => (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '2rem'
    }}>
      <div style={{
        background: 'rgba(30, 41, 59, 0.95)',
        border: '1px solid rgba(148, 163, 184, 0.2)',
        borderRadius: '12px',
        padding: '3rem',
        maxWidth: '400px',
        width: '100%'
      }}>
        <h2 style={{ fontSize: '28px', fontWeight: 'bold', color: 'white', marginBottom: '2rem', textAlign: 'center' }}>
          {isSignUp ? 'Create Account' : 'Sign In'}
        </h2>

        {error && (
          <div style={{
            background: 'rgba(239, 68, 68, 0.1)',
            border: '1px solid #ef4444',
            borderRadius: '8px',
            padding: '1rem',
            marginBottom: '1rem',
            color: '#fca5a5',
            fontSize: '14px'
          }}>
            {error}
          </div>
        )}

        <form onSubmit={handleAuth}>
          {isSignUp && (
            <input
              type="text"
              placeholder="Full Name"
              value={authForm.name}
              onChange={(e) => setAuthForm({ ...authForm, name: e.target.value })}
              style={{
                width: '100%',
                padding: '0.75rem',
                marginBottom: '1rem',
                background: 'rgba(15, 23, 42, 0.5)',
                border: '1px solid rgba(148, 163, 184, 0.2)',
                borderRadius: '8px',
                color: 'white',
                boxSizing: 'border-box'
              }}
              required
            />
          )}

          <input
            type="email"
            placeholder="Email"
            value={authForm.email}
            onChange={(e) => setAuthForm({ ...authForm, email: e.target.value })}
            style={{
              width: '100%',
              padding: '0.75rem',
              marginBottom: '1rem',
              background: 'rgba(15, 23, 42, 0.5)',
              border: '1px solid rgba(148, 163, 184, 0.2)',
              borderRadius: '8px',
              color: 'white',
              boxSizing: 'border-box'
            }}
            required
          />

          <input
            type="password"
            placeholder="Password"
            value={authForm.password}
            onChange={(e) => setAuthForm({ ...authForm, password: e.target.value })}
            style={{
              width: '100%',
              padding: '0.75rem',
              marginBottom: '1rem',
              background: 'rgba(15, 23, 42, 0.5)',
              border: '1px solid rgba(148, 163, 184, 0.2)',
              borderRadius: '8px',
              color: 'white',
              boxSizing: 'border-box'
            }}
            required
          />

          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%',
              padding: '0.75rem',
              background: '#10b981',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: 'pointer',
              fontWeight: 'bold',
              opacity: loading ? 0.5 : 1
            }}
          >
            {loading ? 'Loading...' : (isSignUp ? 'Sign Up' : 'Sign In')}
          </button>
        </form>

        <p style={{ marginTop: '1rem', textAlign: 'center', color: '#94a3b8' }}>
          {isSignUp ? 'Already have an account?' : "Don't have an account?"}
          <button
            onClick={() => setIsSignUp(!isSignUp)}
            style={{
              background: 'none',
              border: 'none',
              color: '#10b981',
              cursor: 'pointer',
              marginLeft: '0.5rem',
              fontWeight: 'bold'
            }}
          >
            {isSignUp ? 'Sign In' : 'Sign Up'}
          </button>
        </p>

        <button
          onClick={() => setPage('landing')}
          style={{
            width: '100%',
            marginTop: '1rem',
            padding: '0.75rem',
            background: 'transparent',
            color: '#94a3b8',
            border: '1px solid rgba(148, 163, 184, 0.2)',
            borderRadius: '8px',
            cursor: 'pointer'
          }}
        >
          Back to Landing
        </button>
      </div>
    </div>
  );

  // ==================== DASHBOARD ====================
  const Dashboard = () => (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)' }}>
      <div style={{
        background: 'rgba(15, 23, 42, 0.95)',
        borderBottom: '1px solid rgba(148, 163, 184, 0.1)',
        padding: '1.5rem 2rem',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#10b981' }}>
          Bailey's Gauge
        </div>
        <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
          <span style={{ color: '#94a3b8' }}>
            {user?.name} • <span style={{ color: '#10b981', fontWeight: 'bold' }}>{(user?.plan || 'free').toUpperCase()}</span>
          </span>
          {user?.plan === 'free' && (
            <button
              onClick={() => handleUpgrade('pro')}
              style={{
                padding: '0.5rem 1rem',
                background: '#10b981',
                color: 'white',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                fontWeight: 'bold',
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem'
              }}
            >
              <Zap size={16} /> Upgrade
            </button>
          )}
          <button
            onClick={handleLogout}
            style={{
              padding: '0.5rem 1rem',
              background: 'transparent',
              color: '#ef4444',
              border: '1px solid #ef4444',
              borderRadius: '6px',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              gap: '0.5rem'
            }}
          >
            <LogOut size={16} /> Logout
          </button>
        </div>
      </div>

      <div style={{ maxWidth: '1400px', margin: '0 auto', padding: '2rem' }}>
        <h1 style={{ fontSize: '32px', fontWeight: 'bold', color: 'white', marginBottom: '2rem' }}>
          Stock Scanner Dashboard
        </h1>

        {error && (
          <div style={{
            background: 'rgba(239, 68, 68, 0.1)',
            border: '1px solid #ef4444',
            borderRadius: '8px',
            padding: '1rem',
            marginBottom: '1rem',
            color: '#fca5a5'
          }}>
            {error}
          </div>
        )}

        <div style={{
          background: 'rgba(30, 41, 59, 0.8)',
          border: '1px solid rgba(148, 163, 184, 0.2)',
          borderRadius: '12px',
          padding: '2rem',
          marginBottom: '2rem'
        }}>
          <h2 style={{ color: 'white', marginBottom: '1rem' }}>Quick Scan</h2>
          <form onSubmit={handleScan} style={{ display: 'flex', gap: '1rem' }}>
            <input
              type="text"
              placeholder="Enter tickers separated by commas"
              value={scanInput}
              onChange={(e) => setScanInput(e.target.value)}
              style={{
                flex: 1,
                padding: '0.75rem',
                background: 'rgba(15, 23, 42, 0.5)',
                border: '1px solid rgba(148, 163, 184, 0.2)',
                borderRadius: '8px',
                color: 'white',
                boxSizing: 'border-box'
              }}
            />
            <button
              type="submit"
              disabled={loading}
              style={{
                padding: '0.75rem 2rem',
                background: '#10b981',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                cursor: 'pointer',
                fontWeight: 'bold',
                opacity: loading ? 0.5 : 1
              }}
            >
              {loading ? 'Scanning...' : 'Scan'}
            </button>
          </form>
        </div>

        {scanResults.length > 0 && (
          <div style={{
            background: 'rgba(30, 41, 59, 0.8)',
            border: '1px solid rgba(148, 163, 184, 0.2)',
            borderRadius: '12px',
            overflow: 'hidden'
          }}>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid rgba(148, 163, 184, 0.2)' }}>
                    <th style={{ padding: '1rem', textAlign: 'left', color: '#94a3b8' }}>Ticker</th>
                    <th style={{ padding: '1rem', textAlign: 'left', color: '#94a3b8' }}>Price</th>
                    <th style={{ padding: '1rem', textAlign: 'left', color: '#94a3b8' }}>Change</th>
                    <th style={{ padding: '1rem', textAlign: 'left', color: '#94a3b8' }}>RSI</th>
                    <th style={{ padding: '1rem', textAlign: 'left', color: '#94a3b8' }}>Signal</th>
                    <th style={{ padding: '1rem', textAlign: 'left', color: '#94a3b8' }}>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {scanResults.map((stock, i) => (
                    <tr key={i} style={{ borderBottom: '1px solid rgba(148, 163, 184, 0.1)' }}>
                      <td style={{ padding: '1rem', color: 'white', fontWeight: 'bold' }}>{stock.ticker}</td>
                      <td style={{ padding: '1rem', color: '#10b981' }}>${stock.price}</td>
                      <td style={{
                        padding: '1rem',
                        color: stock.change > 0 ? '#10b981' : '#ef4444',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.5rem'
                      }}>
                        {stock.change > 0 ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                        {stock.change}%
                      </td>
                      <td style={{ padding: '1rem', color: '#94a3b8' }}>{stock.rsi}</td>
                      <td style={{
                        padding: '1rem',
                        background: stock.signal > 70 ? 'rgba(16, 185, 129, 0.1)' : stock.signal < 30 ? 'rgba(239, 68, 68, 0.1)' : 'transparent',
                        color: stock.signal > 70 ? '#10b981' : stock.signal < 30 ? '#ef4444' : '#94a3b8',
                        borderRadius: '6px',
                        fontWeight: 'bold'
                      }}>
                        {stock.signal}
                      </td>
                      <td style={{ padding: '1rem' }}>
                        <button
                          onClick={() => addToWatchlist(stock.ticker)}
                          style={{
                            padding: '0.5rem 1rem',
                            background: 'transparent',
                            color: '#10b981',
                            border: '1px solid #10b981',
                            borderRadius: '6px',
                            cursor: 'pointer',
                            fontSize: '12px'
                          }}
                        >
                          {watchlist.includes(stock.ticker) ? '★ Saved' : '☆ Add'}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {!loading && scanResults.length === 0 && (
          <div style={{
            background: 'rgba(30, 41, 59, 0.8)',
            border: '1px solid rgba(148, 163, 184, 0.2)',
            borderRadius: '12px',
            padding: '4rem',
            textAlign: 'center',
            color: '#94a3b8'
          }}>
            <p>Enter stock tickers above to start scanning</p>
          </div>
        )}
      </div>
    </div>
  );

  // RENDER
  return (
    <>
      {page === 'landing' && <LandingPage />}
      {page === 'pricing' && <PricingPage />}
      {page === 'auth' && <AuthPage />}
      {page === 'dashboard' && isLoggedIn && <Dashboard />}
    </>
  );
};

export default BaileysGauge;
